    config.try_deserialize()
}

// Example config/default.toml:
// debug = false
//
// [database]
// url = "postgres://localhost/dev"
// pool_size = 10
//
// [server]
// host = "0.0.0.0"
// port = 8080
```

--------------------------------

### Rust: Basic Configuration Builder with Files and Environment Variables

Source: https://context7.com/rust-cli/config-rs/llms.txt

Demonstrates building a configuration using a builder pattern in Rust. It layers default values, TOML file settings, and environment variables prefixed with 'APP_'. Supports accessing individual values and deserializing the entire configuration into a HashMap. Dependencies include the 'config' crate.

```rust
use config::{Config, File, Environment};
use std::collections::HashMap;

// Basic builder pattern with file and environment sources
let settings = Config::builder()
    // Add default values
    .set_default("server.host", "127.0.0.1")? 
    .set_default("server.port", 8080)?
    // Add configuration from TOML file
    .add_source(File::with_name("config/Settings"))
    // Override with environment variables prefixed with APP_
    // Example: APP_SERVER_PORT=9000 overrides server.port
    .add_source(
        Environment::with_prefix("APP")
            .separator("_")  // Use _ to separate nested keys
    )
    // Set explicit overrides (highest priority)
    .set_override("server.debug", true)?
    .build()?;

// Access individual values with type conversion
let host: String = settings.get_string("server.host")?;
let port: i64 = settings.get_int("server.port")?;
let debug: bool = settings.get_bool("server.debug")?;

// Or deserialize entire config into HashMap
let all: HashMap<String, String> = settings.try_deserialize()?;
println!("Configuration: {:?}", all);
```

--------------------------------

### Loading Configuration Files with config-rs

Source: https://context7.com/rust-cli/config-rs/llms.txt

Demonstrates loading configuration from files using the config-rs crate. It covers automatic format detection based on file extensions, explicit format specification, loading from Path objects, and loading from string literals. This method is useful for managing application settings stored in external files.

```rust
use config::{Config, File, FileFormat};
use std::path::Path;
use serde::Deserialize;

#[derive(Debug, Deserialize)]
struct AppConfig {
    app_name: String,
    version: String,
}

// Method 1: Automatic format detection by extension
let config1 = Config::builder()
    .add_source(File::with_name("config/settings"))  // Tries .toml, .json, .yaml, etc.
    .build()?;

// Method 2: Explicit format specification
let config2 = Config::builder()
    .add_source(File::new("config/settings", FileFormat::Json))
    .add_source(File::new("config/overrides", FileFormat::Yaml))
    .build()?;

// Method 3: From Path objects
let config3 = Config::builder()
    .add_source(File::from(Path::new("config/app.toml")))
    .add_source(File::from(Path::new("config/secrets.json")))
    .build()?;

// Method 4: From string literals
let json_config = r#"{"app_name": "MyApp", "version": "1.0.0"}"#;
let config4 = Config::builder()
    .add_source(File::from_str(json_config, FileFormat::Json))
    .build()?;

let app: AppConfig = config4.try_deserialize()?;
println!("App: {} v{}", app.app_name, app.version);
```

--------------------------------

### Parsing Environment Variables with config-rs

Source: https://context7.com/rust-cli/config-rs/llms.txt

Illustrates advanced environment variable parsing using config-rs. It supports prefixes, custom separators, automatic type parsing (integers, floats, booleans), list parsing with custom separators, and case conversion (e.g., SCREAMING_SNAKE to kebab-case). This is ideal for dynamic configuration based on environment settings.

```rust
use config::{Config, Environment};
use serde::Deserialize;

#[derive(Debug, Deserialize)]
struct Redis {
    host: String,
    port: u16,
}

#[derive(Debug, Deserialize)]
struct AppSettings {
    redis: Redis,
    feature_flags: Vec<String>,
    max_connections: i64,
}

// With environment variables:
// APP_REDIS_HOST=localhost
// APP_REDIS_PORT=6379
// APP_FEATURE_FLAGS=auth,logging,metrics
// APP_MAX_CONNECTIONS=100

let config = Config::builder()
    .add_source(
        Environment::with_prefix("APP")
            .separator("_")              // Use _ for nested keys
            .try_parsing(true)           // Parse integers, floats, bools
            .list_separator(",")         // Parse comma-separated lists
            .with_list_parse_key("feature_flags")  // Only parse this key as list
    )
    .build()?;

let settings: AppSettings = config.try_deserialize()?;
assert_eq!(settings.redis.host, "localhost");
assert_eq!(settings.redis.port, 6379);
assert_eq!(settings.feature_flags, vec!["auth", "logging", "metrics"]);
assert_eq!(settings.max_connections, 100);

// Case conversion for kebab-case struct fields
#[derive(Debug, Deserialize)]
struct ServerConfig {
    #[serde(rename = "max-retries")]
    max_retries: u32,
}

// With: APP_MAX_RETRIES=5
let config_with_case = Config::builder()
    .add_source(
        Environment::with_prefix("APP")
            .convert_case(config::Case::Kebab)  // Convert SCREAMING_SNAKE to kebab-case
    )
    .build()?;
```

--------------------------------

### Access nested values and convert types with config-rs (Rust)

Source: https://context7.com/rust-cli/config-rs/llms.txt

Demonstrates retrieving deeply nested configuration values using dot notation and bracket indexing, performing type conversions, and deserializing into a struct. Uses a File source and iterates over tables and arrays. Limitations include runtime type checks and reliance on correct key paths.

```rust
use config::{Config, File, Value};
use std::collections::HashMap;

let config = Config::builder()
    .add_source(File::with_name("config/app"))
    .build()?;

// Access nested values with dot notation
let db_host: String = config.get_string("database.primary.host")?;
let db_port: i64 = config.get_int("database.primary.port")?;

// Access array elements with bracket notation
let first_server: String = config.get_string("servers[0].address")?;
let second_port: i64 = config.get_int("servers[1].port")?;

// Get raw Value for inspection
let db_config = config.get_table("database")?;
for (key, value) in &db_config {
    println!("{}: {:?}", key, value);
}

// Get arrays
let servers: Vec<Value> = config.get_array("servers")?;
println!("Server count: {}", servers.len());

// Type conversion with get generic method
let timeout: f64 = config.get("connection.timeout")?;
let retries: u32 = config.get("connection.retries")?;

// Deserialize partial configuration
#[derive(Debug, serde::Deserialize)]
struct DatabaseConfig {
    host: String,
    port: u16,
    username: String,
}

let db: DatabaseConfig = config.get("database.primary")?;
println!("Database: {}:{}", db.host, db.port);

// Example config/app.toml:
// [database.primary]
// host = "db.example.com"
// port = 5432
// username = "admin"
//
// [[servers]]
// address = "192.168.1.10"
// port = 8080
//
// [[servers]]
// address = "192.168.1.11"
// port = 8081
//
// [connection]
// timeout = 30.5
// retries = 3

```

