use sqlx::PgPool;

use crate::domain::{EmailValidationError, Password, PasswordError, UserId, ValidatedEmail};
use crate::infrastructure::user_repository;

#[derive(Debug, thiserror::Error)]
pub enum RegistrationError {
    #[error("Invalid email: {0}")]
    InvalidEmail(#[from] EmailValidationError),
    #[error("Invalid password: {0}")]
    InvalidPassword(#[from] PasswordError),
    #[error("Passwords do not match")]
    PasswordMismatch,
    #[error("An account with this email already exists")]
    DuplicateEmail,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "register_user",
    skip(pool, password, password_confirm),
    fields(user_email = %email)
)]
pub async fn register_user(
    pool: &PgPool,
    email: String,
    password: String,
    password_confirm: String,
) -> Result<UserId, RegistrationError> {
    let validated_email = ValidatedEmail::parse(email)?;

    if password != password_confirm {
        return Err(RegistrationError::PasswordMismatch);
    }

    let validated_password = Password::parse(password)?;

    let password_hash = validated_password
        .hash()
        .map_err(RegistrationError::Unexpected)?;

    let user_id = UserId::new();

    user_repository::insert_user(pool, &user_id, &validated_email, &password_hash)
        .await
        .map_err(|e| {
            if is_unique_violation(&e) {
                RegistrationError::DuplicateEmail
            } else {
                RegistrationError::Unexpected(anyhow::anyhow!("Database error: {e}"))
            }
        })?;

    tracing::info!("New user registered");

    Ok(user_id)
}

fn is_unique_violation(err: &sqlx::Error) -> bool {
    if let sqlx::Error::Database(db_err) = err {
        db_err.code().as_deref() == Some("23505")
    } else {
        false
    }
}

use sqlx::PgPool;
use uuid::Uuid;

use crate::domain::{PasswordHash_, UserId, ValidatedEmail};

pub struct UserRecord {
    pub id: Uuid,
    pub email: String,
    pub password_hash: String,
}

pub async fn insert_user(
    pool: &PgPool,
    id: &UserId,
    email: &ValidatedEmail,
    password_hash: &PasswordHash_,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"INSERT INTO users (id, email, password_hash) VALUES ($1, $2, $3)"#,
        id.as_uuid(),
        email.as_str(),
        password_hash.as_str(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn find_user_by_email(
    pool: &PgPool,
    email: &str,
) -> Result<Option<UserRecord>, sqlx::Error> {
    let record = sqlx::query_as!(
        UserRecord,
        r#"SELECT id, email, password_hash FROM users WHERE email = $1"#,
        email,
    )
    .fetch_optional(pool)
    .await?;
    Ok(record)
}

CREATE TABLE users (
    id UUID PRIMARY KEY,
    email TEXT NOT NULL UNIQUE,
    password_hash TEXT NOT NULL,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

