     1→use axum::Router;
     2→use sqlx::postgres::PgPoolOptions;
     3→use sqlx::PgPool;
     4→use tokio::net::TcpListener;
     5→use tower_http::request_id::{MakeRequestUuid, PropagateRequestIdLayer, SetRequestIdLayer};
     6→use tower_http::services::ServeDir;
     7→use tower_http::trace::TraceLayer;
     8→
     9→use crate::configuration::Settings;
    10→use crate::routes::{get_register, health_check, index, post_register};
    11→
    12→pub struct Application {
    13→    listener: TcpListener,
    14→    pool: PgPool,
    15→}
    16→
    17→impl Application {
    18→    pub async fn build(settings: &Settings) -> Result<Self, anyhow::Error> {
    19→        let pool = PgPoolOptions::new()
    20→            .max_connections(5)
    21→            .connect_with(settings.database.connect_options())
    22→            .await?;
    23→
    24→        sqlx::migrate!("./migrations").run(&pool).await?;
    25→
    26→        let address = format!(
    27→            "{}:{}",
    28→            settings.application.host, settings.application.port
    29→        );
    30→        let listener = TcpListener::bind(&address).await?;
    31→
    32→        tracing::info!("Listening on {}", listener.local_addr()?);
    33→
    34→        Ok(Self { listener, pool })
    35→    }
    36→
    37→    pub fn port(&self) -> u16 {
    38→        self.listener.local_addr().unwrap().port()
    39→    }
    40→
    41→    pub fn router(pool: PgPool) -> Router {
    42→        let x_request_id = axum::http::HeaderName::from_static("x-request-id");
    43→
    44→        Router::new()
    45→            .route("/", axum::routing::get(index))
    46→            .route(
    47→                "/register",
    48→                axum::routing::get(get_register).post(post_register),
    49→            )
    50→            .route("/health_check", axum::routing::get(health_check))
    51→            .nest_service("/static", ServeDir::new("static"))
    52→            .layer(TraceLayer::new_for_http())
    53→            .layer(PropagateRequestIdLayer::new(x_request_id.clone()))
    54→            .layer(SetRequestIdLayer::new(x_request_id, MakeRequestUuid))
    55→            .with_state(pool)
    56→    }
    57→
    58→    pub async fn run(self) -> Result<(), std::io::Error> {
    59→        let router = Self::router(self.pool);
    60→        axum::serve(self.listener, router).await
