     1→use async_trait::async_trait;
     2→use sqlx::{PgConnection, PgPool};
     3→use time::OffsetDateTime;
     4→use tower_sessions_core::{
     5→    session::{Id, Record},
     6→    session_store, ExpiredDeletion, SessionStore,
     7→};
     8→
     9→use crate::SqlxStoreError;
    10→
    11→/// A PostgreSQL session store.
    12→#[derive(Clone, Debug)]
    13→pub struct PostgresStore {
    14→    pool: PgPool,
    15→    schema_name: String,
    16→    table_name: String,
    17→}
    18→
    19→impl PostgresStore {
    20→    /// Create a new PostgreSQL store with the provided connection pool.
    21→    ///
    22→    /// # Examples
    23→    ///
    24→    /// ```rust,no_run
    25→    /// use tower_sessions_sqlx_store::{sqlx::PgPool, PostgresStore};
    26→    ///
    27→    /// # tokio_test::block_on(async {
    28→    /// let database_url = std::option_env!("DATABASE_URL").unwrap();
    29→    /// let pool = PgPool::connect(database_url).await.unwrap();
    30→    /// let session_store = PostgresStore::new(pool);
    31→    /// # })
    32→    /// ```
    33→    pub fn new(pool: PgPool) -> Self {
    34→        Self {
    35→            pool,
    36→            schema_name: "tower_sessions".to_string(),
    37→            table_name: "session".to_string(),
    38→        }
    39→    }
    40→
    41→    /// Set the session table schema name with the provided name.
    42→    pub fn with_schema_name(mut self, schema_name: impl AsRef<str>) -> Result<Self, String> {
    43→        let schema_name = schema_name.as_ref();
    44→        if !is_valid_identifier(schema_name) {
    45→            return Err(format!(
    46→                "Invalid schema name '{}'. Schema names must start with a letter or underscore \
    47→                 (including letters with diacritical marks and non-Latin letters).Subsequent \
    48→                 characters can be letters, underscores, digits (0-9), or dollar signs ($).",
    49→                schema_name
    50→            ));
    51→        }
    52→
    53→        schema_name.clone_into(&mut self.schema_name);
    54→        Ok(self)
    55→    }
    56→
    57→    /// Set the session table name with the provided name.
    58→    pub fn with_table_name(mut self, table_name: impl AsRef<str>) -> Result<Self, String> {
    59→        let table_name = table_name.as_ref();
    60→        if !is_valid_identifier(table_name) {
    61→            return Err(format!(
    62→                "Invalid table name '{}'. Table names must start with a letter or underscore \
    63→                 (including letters with diacritical marks and non-Latin letters).Subsequent \
    64→                 characters can be letters, underscores, digits (0-9), or dollar signs ($).",
    65→                table_name
    66→            ));
    67→        }
    68→
    69→        table_name.clone_into(&mut self.table_name);
    70→        Ok(self)
    71→    }
    72→
    73→    /// Migrate the session schema.
    74→    ///
    75→    /// # Examples
    76→    ///
    77→    /// ```rust,no_run
    78→    /// use tower_sessions_sqlx_store::{sqlx::PgPool, PostgresStore};
    79→    ///
    80→    /// # tokio_test::block_on(async {
    81→    /// let database_url = std::option_env!("DATABASE_URL").unwrap();
    82→    /// let pool = PgPool::connect(database_url).await.unwrap();
    83→    /// let session_store = PostgresStore::new(pool);
    84→    /// session_store.migrate().await.unwrap();
    85→    /// # })
    86→    /// ```
    87→    pub async fn migrate(&self) -> sqlx::Result<()> {
    88→        let mut tx = self.pool.begin().await?;
    89→
    90→        let create_schema_query = format!(
    91→            r#"create schema if not exists "{schema_name}""#,
    92→            schema_name = self.schema_name,
    93→        );
    94→        // Concurrent create schema may fail due to duplicate key violations.
    95→        //
    96→        // This works around that by assuming the schema must exist on such an error.
    97→        if let Err(err) = sqlx::query(&create_schema_query).execute(&mut *tx).await {
    98→            if !err
    99→                .to_string()
   100→                .contains("duplicate key value violates unique constraint")
   101→            {
   102→                return Err(err);
   103→            }
   104→
   105→            return Ok(());
   106→        }
   107→
   108→        let create_table_query = format!(
   109→            r#"
   110→            create table if not exists "{schema_name}"."{table_name}"
   111→            (
   112→                id text primary key not null,
   113→                data bytea not null,
   114→                expiry_date timestamptz not null
   115→            )
   116→            "#,
   117→            schema_name = self.schema_name,
   118→            table_name = self.table_name
   119→        );
   120→        sqlx::query(&create_table_query).execute(&mut *tx).await?;
   121→
   122→        tx.commit().await?;
   123→
   124→        Ok(())
   125→    }
   126→
   127→    async fn id_exists(&self, conn: &mut PgConnection, id: &Id) -> session_store::Result<bool> {
   128→        let query = format!(
   129→            r#"
   130→            select exists(select 1 from "{schema_name}"."{table_name}" where id = $1)
   131→            "#,
   132→            schema_name = self.schema_name,
   133→            table_name = self.table_name
   134→        );
   135→
   136→        Ok(sqlx::query_scalar(&query)
   137→            .bind(id.to_string())
   138→            .fetch_one(conn)
   139→            .await
   140→            .map_err(SqlxStoreError::Sqlx)?)
   141→    }
   142→
   143→    async fn save_with_conn(
   144→        &self,
   145→        conn: &mut PgConnection,
   146→        record: &Record,
   147→    ) -> session_store::Result<()> {
   148→        let query = format!(
   149→            r#"
   150→            insert into "{schema_name}"."{table_name}" (id, data, expiry_date)
   151→            values ($1, $2, $3)
   152→            on conflict (id) do update
   153→            set
   154→              data = excluded.data,
   155→              expiry_date = excluded.expiry_date
   156→            "#,
   157→            schema_name = self.schema_name,
   158→            table_name = self.table_name
   159→        );
   160→        sqlx::query(&query)
   161→            .bind(record.id.to_string())
   162→            .bind(rmp_serde::to_vec(&record).map_err(SqlxStoreError::Encode)?)
   163→            .bind(record.expiry_date)
   164→            .execute(conn)
   165→            .await
   166→            .map_err(SqlxStoreError::Sqlx)?;
   167→
   168→        Ok(())
   169→    }
   170→}
   171→
   172→#[async_trait]
   173→impl ExpiredDeletion for PostgresStore {
   174→    async fn delete_expired(&self) -> session_store::Result<()> {
   175→        let query = format!(
   176→            r#"
   177→            delete from "{schema_name}"."{table_name}"
   178→            where expiry_date < (now() at time zone 'utc')
   179→            "#,
   180→            schema_name = self.schema_name,
   181→            table_name = self.table_name
   182→        );
   183→        sqlx::query(&query)
   184→            .execute(&self.pool)
   185→            .await
   186→            .map_err(SqlxStoreError::Sqlx)?;
   187→        Ok(())
   188→    }
   189→}
   190→
   191→#[async_trait]
   192→impl SessionStore for PostgresStore {
   193→    async fn create(&self, record: &mut Record) -> session_store::Result<()> {
   194→        let mut tx = self.pool.begin().await.map_err(SqlxStoreError::Sqlx)?;
   195→
   196→        while self.id_exists(&mut tx, &record.id).await? {
   197→            record.id = Id::default();
   198→        }
   199→        self.save_with_conn(&mut tx, record).await?;
   200→
   201→        tx.commit().await.map_err(SqlxStoreError::Sqlx)?;
   202→
   203→        Ok(())
   204→    }
   205→
   206→    async fn save(&self, record: &Record) -> session_store::Result<()> {
   207→        let mut conn = self.pool.acquire().await.map_err(SqlxStoreError::Sqlx)?;
   208→        self.save_with_conn(&mut conn, record).await
   209→    }
   210→
   211→    async fn load(&self, session_id: &Id) -> session_store::Result<Option<Record>> {
   212→        let query = format!(
   213→            r#"
   214→            select data from "{schema_name}"."{table_name}"
   215→            where id = $1 and expiry_date > $2
   216→            "#,
   217→            schema_name = self.schema_name,
   218→            table_name = self.table_name
   219→        );
   220→        let record_value: Option<(Vec<u8>,)> = sqlx::query_as(&query)
   221→            .bind(session_id.to_string())
   222→            .bind(OffsetDateTime::now_utc())
   223→            .fetch_optional(&self.pool)
   224→            .await
   225→            .map_err(SqlxStoreError::Sqlx)?;
   226→
   227→        if let Some((data,)) = record_value {
   228→            Ok(Some(
