    12→use crate::routes::{
    13→    get_login, get_register, get_todos_page, health_check, index, post_login, post_logout,
    14→    post_register, post_todo,
    15→};
    16→
    17→pub struct Application {
    18→    listener: TcpListener,
    19→    pool: PgPool,
    20→}
    21→
    22→impl Application {
    23→    pub async fn build(settings: &Settings) -> Result<Self, anyhow::Error> {
    24→        let pool = PgPoolOptions::new()
    25→            .max_connections(5)
    26→            .connect_with(settings.database.connect_options())
    27→            .await?;
    28→
    29→        sqlx::migrate!("./migrations").run(&pool).await?;
    30→
    31→        let session_store = PostgresStore::new(pool.clone());
    32→        session_store.migrate().await?;
    33→
    34→        let address = format!(
    35→            "{}:{}",
    36→            settings.application.host, settings.application.port
    37→        );
    38→        let listener = TcpListener::bind(&address).await?;
    39→
    40→        tracing::info!("Listening on {}", listener.local_addr()?);
    41→
    42→        Ok(Self { listener, pool })
    43→    }
    44→
    45→    pub fn port(&self) -> u16 {
    46→        self.listener.local_addr().unwrap().port()
    47→    }
    48→
    49→    pub fn router(pool: PgPool) -> Router {
    50→        let x_request_id = axum::http::HeaderName::from_static("x-request-id");
    51→
    52→        let session_store = PostgresStore::new(pool.clone());
    53→        let session_layer = SessionManagerLayer::new(session_store);
    54→
    55→        Router::new()
    56→            .route("/", axum::routing::get(index))
    57→            .route(
    58→                "/register",
    59→                axum::routing::get(get_register).post(post_register),
    60→            )
    61→            .route("/login", axum::routing::get(get_login).post(post_login))
    62→            .route("/logout", axum::routing::post(post_logout))
    63→            .route("/health_check", axum::routing::get(health_check))
    64→            .nest_service("/static", ServeDir::new("static"))
