    10→use crate::services::todo_service::{add_todo, get_todos, AddTodoError};
    11→
    12→/// View model for a single todo item in the template.
    13→pub struct TodoItemView {
    14→    #[allow(dead_code)] // Used in complete/delete actions (Task #8, #9)
    15→    pub id: String,
    16→    pub title: String,
    17→    pub is_completed: bool,
    18→}
    19→
    20→impl From<&TodoItem> for TodoItemView {
    21→    fn from(item: &TodoItem) -> Self {
    22→        Self {
    23→            id: item.id().as_uuid().to_string(),
    24→            title: item.title().as_str().to_string(),
    25→            is_completed: item.is_completed(),
    26→        }
    27→    }
    28→}
    29→
    30→#[derive(Template)]
    31→#[template(path = "todos.html")]
    32→pub struct TodosTemplate {
    33→    pub todos: Vec<TodoItemView>,
    34→    pub error_message: Option<String>,
    35→}
    36→
    37→pub async fn get_todos_page(
    38→    AuthenticatedUser(user_id): AuthenticatedUser,
    39→    State(pool): State<PgPool>,
    40→) -> Result<impl IntoResponse, TodosError> {
    41→    let todos = get_todos(&pool, &user_id)
    42→        .await
    43→        .map_err(TodosError::Unexpected)?;
    44→
    45→    let todo_views: Vec<TodoItemView> = todos.iter().map(TodoItemView::from).collect();
    46→
    47→    let template = TodosTemplate {
    48→        todos: todo_views,
    49→        error_message: None,
    50→    };
    51→    Ok(Html(template.render()?))
    52→}
    53→
